#include <stdio.h>
#include <stdlib.h>
#define MAXN 100005
#define MOD 1000000007
int graph[MAXN][MAXN];
int visited[MAXN];
int dfs(int node, int n) {
    visited[node] = 1;
    int size = 1;
    for (int i = 1; i <= n; i++) {
        if (graph[node][i] && !visited[i]) {
            size += dfs(i, n);
        }
    }
    return size;
}
int main() {
    int T;
    scanf("%d", &T);
    while (T--) {
        int N, M;
        scanf("%d %d", &N, &M);
        for (int i = 1; i <= N; i++) {
            for (int j = 1; j <= N; j++) {
                graph[i][j] = 0;
            }
        }
        for (int i = 0; i < M; i++) {
            int u, v;
            scanf("%d %d", &u, &v);
            graph[u][v] = graph[v][u] = 1;
        }
        int components = 0;
        long long ways = 1;
        for (int i = 1; i <= N; i++) {
            if (!visited[i]) {
                int size = dfs(i, N);
                components++;
                ways = (ways * size) % MOD;
            }
        }
        printf("%d %lld\n", components, ways);
        for (int i = 1; i <= N; i++) {
            visited[i] = 0;
        }
    }
    return 0;
}

