using namespace std;
int dfs(int node, vector<vector<int>> &graph, vector<bool> &visited) {
    visited[node] = true;
    int size = 1;
    for (int i = 0; i < graph[node].size(); i++) {
        if (!visited[graph[node][i]]) {
            size += dfs(graph[node][i], graph, visited);
        }
    }
    return size;
}
